/// Generate a type-driven error variant for mock injection.
///
/// Dispatches based on return type structure:
/// - Object with "status" field → HTTP error (400/500 variants)
/// - Result complex type → Err variant
/// - Nullable → null
/// - Unknown → category-aware error shape
/// - Fallback → ThrowError behavior (returns None, caller uses ThrowError MockBehavior)
fn generate_error_variant(
    return_type: &TypeInfo,
    category: IoCategory,
    rng: &mut impl Rng,
) -> Option<Value> {
    match return_type {
        // Nullable types: error case is null
        TypeInfo::Nullable { .. } => Some(Value::Null),

        // Result type: Err variant
        TypeInfo::Complex { kind: ComplexKind::Result, .. } => {
            Some(json!({"__complex_type": "result", "ok": false, "value": "injected error"}))
        }

        // Object with "status" field: HTTP error responses
        TypeInfo::Object { fields } => {
            if fields.iter().any(|(name, _)| name == "status") {
                let codes = [400, 401, 403, 404, 500, 502, 503];
                let code = codes[rng.random_range(0..codes.len())];
                Some(json!({"status": code, "data": null, "error": "mock error"}))
            } else {
                None // no obvious error shape, caller should use ThrowError
            }
        }

        // Union with Error variant: pick an error variant
        TypeInfo::Union { variants } => {
            let (error_indices, _) = partition_error_variants(variants);
            if let Some(&idx) = error_indices.first() {
                let metadata = match &variants[idx] {
                    TypeInfo::Complex { metadata, .. } => metadata.clone(),
                    _ => serde_json::Map::new(),
                };
                Some(generate_error(&metadata, rng))
            } else {
                None
            }
        }

        // Unknown type: category-aware error shapes
        TypeInfo::Unknown => Some(category_shaped_error_value(category, rng)),

        // No type-driven error shape available
        _ => None,
    }
}

/// Category-aware error value for Unknown return types.
fn category_shaped_error_value(category: IoCategory, rng: &mut impl Rng) -> Value {
    match category {
        IoCategory::Network => {
            let codes = [400, 401, 403, 404, 500, 502, 503];
            let code = codes[rng.random_range(0..codes.len())];
            json!({"status": code, "data": null, "error": "mock error"})
        }
        IoCategory::Database => {
            json!({"error": "connection refused", "rows": null})
        }
        IoCategory::FileSystem => {
            json!({"__complex_type": "error", "class": "Error", "message": "ENOENT: no such file or directory"})
        }
        IoCategory::PureUtility | IoCategory::ExternalOther => {
            json!({"__complex_type": "error", "class": "Error", "message": "mock error"})
        }
    }
}
